#include <bits/stdc++.h>
using namespace std;
const int N=100005,K=20;
long long n,k,f[K][N],dp[1<<16],a[K],b[N],ans=-1;
int main()
{
    cin>>k>>n;
    for(int i=1;i<=k;i++) cin>>a[i];
    for(int i=1;i<=n;i++) cin>>b[i];
    for(int i=1;i<=k;i++)
    {
        long long num=0,sum=0;
        for(int j=1;j<=n;sum-=b[j++])
        {
            while(sum<a[i]&&num<=n)
            {
                num++;
                sum+=b[i];
            }
            f[i][j]=num-1;
        }
    }
    dp[0]=1;
    for(int i=0;i<(1<<k);i++)
    {
        for(int j=0;j<k;j++)
        {
            if(!(i&(1<<j))) continue;
            dp[i]=max(dp[i],f[j][dp[i^(1<<j)]]);
        }
        dp[i]++;
        if(dp[i]==n+1)
        {
            long long sum=0;
            for(int j=0;j<k;j++)
            {
                if(!(i&(1<<j))) sum+=a[j];
            }
            ans=max(ans,sum);
        }

    }
    cout<<ans;
    return 0;
}
